import{_ as n,O as r,H as o,f as s,b as t,j as l,k as i,i as h}from"./chunks/framework.Pt2pSV98.js";const q=JSON.parse('{"title":"AI 发展历程","description":"从 1956 到 2025，人工智能的发展脉络与关键里程碑","frontmatter":{"title":"AI 发展历程","description":"从 1956 到 2025，人工智能的发展脉络与关键里程碑","difficulty":"beginner"},"headers":[],"relativePath":"terms/history.md","filePath":"terms/history.md"}'),g={name:"terms/history.md"};function p(d,a,u,c,A,b){const e=r("DifficultyBadge");return o(),s("div",null,[a[0]||(a[0]=t("h1",{id:"📜-ai-发展历程",tabindex:"-1"},[l("📜 AI 发展历程 "),t("a",{class:"header-anchor",href:"#📜-ai-发展历程","aria-label":'Permalink to "📜 AI 发展历程"'},"​")],-1)),a[1]||(a[1]=t("p",null,'人工智能从 1956 年正式诞生到今天，经历了三次浪潮和两次寒冬。了解这段历史，能帮你理解每一个概念"为什么重要"。',-1)),i(e,{level:"beginner"}),a[2]||(a[2]=h(`<hr><h2 id="🌱-萌芽期-1950s-—-1960s" tabindex="-1">🌱 萌芽期（1950s — 1960s） <a class="header-anchor" href="#🌱-萌芽期-1950s-—-1960s" aria-label="Permalink to &quot;🌱 萌芽期（1950s — 1960s）&quot;">​</a></h2><h3 id="_1950-图灵测试" tabindex="-1">1950：图灵测试 <a class="header-anchor" href="#_1950-图灵测试" aria-label="Permalink to &quot;1950：图灵测试&quot;">​</a></h3><p>艾伦·图灵发表《计算机器与智能》，提出&quot;机器能思考吗？&quot;并设计了<strong>图灵测试</strong>——如果一台机器能在对话中让人类无法分辨它是人还是机器，就认为它具有智能。这被认为是 AI 的思想起点。</p><h3 id="_1956-dartmouth-会议-—-ai-正式诞生" tabindex="-1">1956：Dartmouth 会议 — AI 正式诞生 <a class="header-anchor" href="#_1956-dartmouth-会议-—-ai-正式诞生" aria-label="Permalink to &quot;1956：Dartmouth 会议 — AI 正式诞生&quot;">​</a></h3><p>约翰·麦卡锡、马文·明斯基等科学家在 Dartmouth 学院召开夏季研讨会，<strong>首次提出&quot;人工智能&quot;（Artificial Intelligence）这一术语</strong>。这一天被公认为 AI 的诞生日。</p><h3 id="_1958-感知机" tabindex="-1">1958：感知机 <a class="header-anchor" href="#_1958-感知机" aria-label="Permalink to &quot;1958：感知机&quot;">​</a></h3><p>弗兰克·罗森布拉特发明<strong>感知机（Perceptron）</strong>，这是最早的神经网络雏形，能进行简单的模式识别。</p><h3 id="_1966-eliza-聊天机器人" tabindex="-1">1966：ELIZA 聊天机器人 <a class="header-anchor" href="#_1966-eliza-聊天机器人" aria-label="Permalink to &quot;1966：ELIZA 聊天机器人&quot;">​</a></h3><p>MIT 的约瑟夫·维森鲍姆开发 ELIZA，模拟心理治疗师对话。这是<strong>最早的对话系统</strong>。</p><hr><h2 id="❄️-第一次寒冬-1970s-—-1980s" tabindex="-1">❄️ 第一次寒冬（1970s — 1980s） <a class="header-anchor" href="#❄️-第一次寒冬-1970s-—-1980s" aria-label="Permalink to &quot;❄️ 第一次寒冬（1970s — 1980s）&quot;">​</a></h2><h3 id="_1970-lighthill-报告" tabindex="-1">1970：Lighthill 报告 <a class="header-anchor" href="#_1970-lighthill-报告" aria-label="Permalink to &quot;1970：Lighthill 报告&quot;">​</a></h3><p>英国政府发布 Lighthill 报告，指出 AI 研究&quot;未能实现其宏伟承诺&quot;，导致英国大幅削减 AI 研究经费，引发<strong>第一次 AI 寒冬</strong>。感知机被证明无法解决异或（XOR）问题，神经网络研究陷入低谷。</p><h3 id="_1980-专家系统兴起" tabindex="-1">1980：专家系统兴起 <a class="header-anchor" href="#_1980-专家系统兴起" aria-label="Permalink to &quot;1980：专家系统兴起&quot;">​</a></h3><p><strong>专家系统（Expert Systems）</strong> 开始商业化，通过知识库+推理引擎解决特定领域问题。MYCIN（医疗诊断）、XCON（计算机配置）是代表。AI 迎来短暂春天。</p><h3 id="_1986-反向传播算法" tabindex="-1">1986：反向传播算法 <a class="header-anchor" href="#_1986-反向传播算法" aria-label="Permalink to &quot;1986：反向传播算法&quot;">​</a></h3><p>辛顿（Hinton）、鲁梅尔哈特等人重新提出<strong>反向传播（Backpropagation）</strong> 算法，解决了多层神经网络的训练问题。但这时的算力还远远不够。</p><h3 id="_1988-第二次寒冬" tabindex="-1">1988：第二次寒冬 <a class="header-anchor" href="#_1988-第二次寒冬" aria-label="Permalink to &quot;1988：第二次寒冬&quot;">​</a></h3><p>专家系统的维护成本高、应用范围窄等局限性暴露，日本第五代计算机项目失败，AI 研究再次陷入<strong>第二次寒冬</strong>。</p><hr><h2 id="🚀-崛起期-1997-—-2011" tabindex="-1">🚀 崛起期（1997 — 2011） <a class="header-anchor" href="#🚀-崛起期-1997-—-2011" aria-label="Permalink to &quot;🚀 崛起期（1997 — 2011）&quot;">​</a></h2><h3 id="_1997-深蓝击败国际象棋世界冠军" tabindex="-1">1997：深蓝击败国际象棋世界冠军 <a class="header-anchor" href="#_1997-深蓝击败国际象棋世界冠军" aria-label="Permalink to &quot;1997：深蓝击败国际象棋世界冠军&quot;">​</a></h3><p>IBM 的<strong>深蓝（DeepBlue）</strong> 击败卡斯帕罗夫，这是 AI 首次在智力博弈中击败人类世界冠军。用的是搜索+评估函数的方法，而非深度学习。</p><h3 id="_2006-深度学习重新出发" tabindex="-1">2006：深度学习重新出发 <a class="header-anchor" href="#_2006-深度学习重新出发" aria-label="Permalink to &quot;2006：深度学习重新出发&quot;">​</a></h3><p>辛顿发表深度信念网络论文，提出逐层预训练的方法，<strong>&quot;深度学习&quot;（Deep Learning）</strong> 概念正式登场。算力（GPU）的提升让深度网络训练成为可能。</p><hr><h2 id="🔥-深度学习革命-2012-—-2021" tabindex="-1">🔥 深度学习革命（2012 — 2021） <a class="header-anchor" href="#🔥-深度学习革命-2012-—-2021" aria-label="Permalink to &quot;🔥 深度学习革命（2012 — 2021）&quot;">​</a></h2><h3 id="_2012-alexnet-引爆深度学习" tabindex="-1">2012：AlexNet 引爆深度学习 <a class="header-anchor" href="#_2012-alexnet-引爆深度学习" aria-label="Permalink to &quot;2012：AlexNet 引爆深度学习&quot;">​</a></h3><p>辛顿的学生 Alex Krizhevsky 使用 GPU 训练的卷积神经网络 <strong>AlexNet</strong> 在 ImageNet 图像识别竞赛中远超第二名（错误率 15.3% vs 26.2%），<strong>深度学习时代正式开启</strong>。</p><ul><li>关键推动力：GPU（NVIDIA CUDA）、大规模标注数据（ImageNet）</li></ul><h3 id="_2014-gan-—-让-ai-学会创造" tabindex="-1">2014：GAN — 让 AI 学会创造 <a class="header-anchor" href="#_2014-gan-—-让-ai-学会创造" aria-label="Permalink to &quot;2014：GAN — 让 AI 学会创造&quot;">​</a></h3><p>伊恩·古德费洛提出<strong>生成对抗网络（GAN）</strong>，让两个网络互相博弈，一个生成、一个判别，从而学会生成逼真的图像。这是 AI 生成内容的起点。</p><p>同年，<strong>Seq2Seq + Attention</strong> 机制被提出，为机器翻译带来突破。</p><h3 id="_2017-transformer-—-改变一切的论文" tabindex="-1">2017：Transformer — 改变一切的论文 <a class="header-anchor" href="#_2017-transformer-—-改变一切的论文" aria-label="Permalink to &quot;2017：Transformer — 改变一切的论文&quot;">​</a></h3><p>Google 团队发表论文 <strong>《Attention Is All You Need》</strong>，提出 <strong>Transformer 架构</strong>。核心创新：</p><ul><li>用<strong>自注意力机制</strong>替代 RNN 的循环结构</li><li>可以并行计算，训练效率大幅提升</li><li>为后续所有大模型（GPT、BERT、Claude 等）奠定架构基础</li></ul><p><strong>这是 AI 历史上最重要的论文之一。</strong></p><h3 id="_2018-bert-gpt" tabindex="-1">2018：BERT + GPT <a class="header-anchor" href="#_2018-bert-gpt" aria-label="Permalink to &quot;2018：BERT + GPT&quot;">​</a></h3><ul><li><strong>BERT</strong>（Google）：双向预训练模型，在 NLP 的 11 项任务上刷新纪录</li><li><strong>GPT</strong>（OpenAI）：单向自回归预训练模型，证明&quot;更大的模型 + 更多的数据 = 更强的能力&quot;</li></ul><p><strong>预训练 + 微调（Pre-training + Fine-tuning）范式</strong>确立。</p><h3 id="_2020-gpt-3-震撼业界" tabindex="-1">2020：GPT-3 震撼业界 <a class="header-anchor" href="#_2020-gpt-3-震撼业界" aria-label="Permalink to &quot;2020：GPT-3 震撼业界&quot;">​</a></h3><p>OpenAI 发布 <strong>GPT-3</strong>（1750 亿参数），展示了惊人的少样本学习（Few-Shot）能力。模型规模突然变成了最关键的竞争维度。</p><p>同期，<strong>AlphaFold 2</strong>（DeepMind）解决了蛋白质结构预测这一 50 年难题。</p><h3 id="_2021-dall·e-codex" tabindex="-1">2021：DALL·E + Codex <a class="header-anchor" href="#_2021-dall·e-codex" aria-label="Permalink to &quot;2021：DALL·E + Codex&quot;">​</a></h3><ul><li><strong>DALL·E</strong>：文本生成图像，AI 从理解走向创造</li><li><strong>GitHub Copilot（Codex）</strong>：AI 编程助手，改变开发者工作方式</li><li><strong>CLIP</strong>：图文联合 embedding，多模态基础模型</li></ul><hr><h2 id="🌍-全民-ai-时代-2022-—-至今" tabindex="-1">🌍 全民 AI 时代（2022 — 至今） <a class="header-anchor" href="#🌍-全民-ai-时代-2022-—-至今" aria-label="Permalink to &quot;🌍 全民 AI 时代（2022 — 至今）&quot;">​</a></h2><h3 id="_2022-chatgpt-—-iphone-时刻" tabindex="-1">2022：ChatGPT — iPhone 时刻 <a class="header-anchor" href="#_2022-chatgpt-—-iphone-时刻" aria-label="Permalink to &quot;2022：ChatGPT — iPhone 时刻&quot;">​</a></h3><p>2022 年 11 月 30 日，OpenAI 发布 <strong>ChatGPT</strong>（基于 GPT-3.5），5 天注册用户破百万，2 个月月活破亿——史上增长最快的应用。</p><ul><li>关键创新：<strong>RLHF（基于人类反馈的强化学习）</strong> 让模型输出更对齐人类偏好</li><li>影响：AI 从小众技术变成全民话题</li></ul><p>2022 年底，<strong>Stable Diffusion</strong> 开源发布，AI 图像生成进入大众视野。</p><h3 id="_2023-gpt-4-开源浪潮" tabindex="-1">2023：GPT-4 + 开源浪潮 <a class="header-anchor" href="#_2023-gpt-4-开源浪潮" aria-label="Permalink to &quot;2023：GPT-4 + 开源浪潮&quot;">​</a></h3><ul><li><strong>GPT-4</strong>：多模态（文字+图像输入）、逻辑推理大幅提升</li><li><strong>Llama / Mistral / Qwen</strong>：开源模型爆发，推动 AI 民主化</li><li><strong>AutoGPT / Agent</strong>：自主 AI 智能体概念兴起</li><li><strong>RAG 架构</strong>：检索增强生成成为企业落地标准方案</li></ul><h3 id="_2024-多模态-长上下文" tabindex="-1">2024：多模态 + 长上下文 <a class="header-anchor" href="#_2024-多模态-长上下文" aria-label="Permalink to &quot;2024：多模态 + 长上下文&quot;">​</a></h3><ul><li><strong>GPT-4o</strong>：原生多模态、实时语音对话</li><li><strong>Claude 3</strong>：200K 上下文、深度推理标杆</li><li><strong>Gemini 1.5 Pro</strong>：1M 上下文，Google 生态加持</li><li><strong>Sora</strong>：文本生成视频，AI 进入视频时代</li><li><strong>Kimi</strong>：200 万字上下文，国产模型崛起</li><li><strong>Cursor / Windsurf</strong>：AI 原生 IDE 改变编程体验</li></ul><h3 id="_2025-推理-agent-开源平权" tabindex="-1">2025：推理 + Agent + 开源平权 <a class="header-anchor" href="#_2025-推理-agent-开源平权" aria-label="Permalink to &quot;2025：推理 + Agent + 开源平权&quot;">​</a></h3><ul><li><strong>DeepSeek-V3 / R1</strong>：开源模型逼近闭源水平，推理能力爆发的「东方神秘力量」</li><li><strong>CoT / 推理模型</strong>：思维链（Chain-of-Thought）成为标配，o1、DeepSeek-R1 等推理模型引领方向</li><li><strong>Agent 框架成熟</strong>：Multi-Agent、MCP 协议让 AI 自主执行复杂任务成为可能</li><li><strong>MoE 架构普及</strong>：混合专家模型成为大模型标配，效率与性能的平衡点</li></ul><h3 id="_2026-多模态进阶-agent-落地-ai-编程革命" tabindex="-1">2026：多模态进阶 + Agent 落地 + AI 编程革命 <a class="header-anchor" href="#_2026-多模态进阶-agent-落地-ai-编程革命" aria-label="Permalink to &quot;2026：多模态进阶 + Agent 落地 + AI 编程革命&quot;">​</a></h3><ul><li><strong>Claude 4 / GPT-5 / Gemini 2.5 Pro</strong>：新一代旗舰模型在推理、多模态和长上下文上全面突破</li><li><strong>MCP 成为事实标准</strong>：Model Context Protocol 被主流 IDE 和 Agent 框架广泛采纳，AI 工具互联互通</li><li><strong>AI 编程深度变革</strong>：Cursor、Windsurf、OpenCode 从代码补全升级为自主编程 Agent，能独立完成中型项目</li><li><strong>Agent 进入生产环境</strong>：Multi-Agent 系统从概念验证走向实际业务，CrewAI / AutoGen 等框架成熟</li><li><strong>DeepSeek-V4 / Qwen3 / Llama 4</strong>：开源模型在性能上进一步追赶闭源，推理成本持续降低</li><li><strong>AI 视频与音频爆发</strong>：Sora 正式开放、Runway Gen-4、ElevenLabs 语音合成质量突破，多模态创作普及</li><li><strong>AI 编程教育兴起</strong>：越来越多开发者通过 AI 辅助学习编程、用自然语言驱动软件开发</li></ul><hr><h2 id="总结-发展的驱动力" tabindex="-1">总结：发展的驱动力 <a class="header-anchor" href="#总结-发展的驱动力" aria-label="Permalink to &quot;总结：发展的驱动力&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1950s      概念诞生         ← 数学 + 逻辑</span></span>
<span class="line"><span>    ↕</span></span>
<span class="line"><span>1980s      知识驱动         ← 专家系统</span></span>
<span class="line"><span>    ↕</span></span>
<span class="line"><span>2010s      数据 + 算力       ← GPU + 大数据</span></span>
<span class="line"><span>    ↕</span></span>
<span class="line"><span>2020s      规模法则         ← 更大模型 + 更多数据</span></span>
<span class="line"><span>    ↕</span></span>
<span class="line"><span>2025+      推理 + 自主       ← 推理模型 + Agent</span></span>
<span class="line"><span>    ↕</span></span>
<span class="line"><span>2026+      编程 + 多模态     ← AI 编程 + Agent 落地 + MCP 互联</span></span></code></pre></div><p>AI 发展有三个核心驱动力：</p><ol><li><strong>算力</strong>：从 CPU → GPU → TPU → 万卡集群，算力提升了数百万倍</li><li><strong>数据</strong>：从小规模标注 → 互联网级文本 → 多模态海量数据</li><li><strong>算法</strong>：从感知机 → 反向传播 → Transformer → CoT 推理</li></ol><p>了解历史不是为了记住年份，而是明白<strong>我们站在哪里、为什么在这里、接下来可能往哪去</strong>。</p><hr><p>→ 🧭 <a href="/ai-knowledge/roadmap/">返回学习路线图，开始第 1 周</a></p>`,68))])}const m=n(g,[["render",p]]);export{q as __pageData,m as default};
